import type { PathologyType } from './pathology-kb'
import type { InterventionHorizon } from './action-plan'

// ─── T/A/M ───────────────────────────────────────────────────────────────────

export interface TamScore {
  t: number  // Time 1–5
  a: number  // Attention 1–5
  m: number  // Money 1–5
  total: number
}

