    prognosis: '\u05DE\u05D3\u05D9\u05D3\u05EA Edmondson \u05D7\u05D5\u05D6\u05E8\u05EA + Just Culture + \u05D7\u05D9\u05D6\u05D5\u05E7 \u05E2\u05E8\u05D5\u05E5 \u05E7\u05D5\u05DC — 8–12 \u05E9\u05D1\u05D5\u05E2\u05D5\u05EA \u05DC\u05E9\u05D9\u05E4\u05D5\u05E8 \u05E8\u05D0\u05E9\u05D5\u05E0\u05D9.',
